#!/usr/bin/env python
"""
inject_summary.py
=====================================

Purpose:
    Direct JSON injection script for Agent-Driven Distillation.
    Allows an AI Agent (Claude, Gemini, Antigravity) to write a summary
    directly into the RLM cache, bypassing local Ollama and slow HTTP calls.

Layer: Curate / Rlm

Usage:
    python ./scripts/inject_summary.py \
        --profile project \
        --file docs/architecture.md \
        --summary "Dense summary generated by agent..."
"""
import sys
import argparse
import platform
from contextlib import contextmanager
from pathlib import Path
from datetime import datetime

# ─────────────────────────────────────────────────────────────
# Cross-platform file lock shim
# fcntl is POSIX-only; Windows uses a no-op (agent workflows
# are single-process sequential — no concurrent writes needed).
# ─────────────────────────────────────────────────────────────
if platform.system() == "Windows":
    @contextmanager
    def _file_lock(lock_path: Path):
        lock_path.parent.mkdir(parents=True, exist_ok=True)
        with open(lock_path, "w") as _lf:
            yield _lf
else:
    import fcntl
    @contextmanager
    def _file_lock(lock_path: Path):
        lock_path.parent.mkdir(parents=True, exist_ok=True)
        with open(lock_path, "w") as _lf:
            fcntl.flock(_lf, fcntl.LOCK_EX)
            try:
                yield _lf
            finally:
                fcntl.flock(_lf, fcntl.LOCK_UN)

# ============================================================
# PATHS
# ============================================================
def _find_project_root(start_path: Path) -> Path:
    current = start_path.resolve()
    for parent in [current] + list(current.parents):
        if (parent / ".git").is_dir():
            return parent
    return current.parents[3]

PROJECT_ROOT = _find_project_root(Path(__file__))
SCRIPT_DIR = Path(__file__).resolve().parent

try:
    from rlm_config import (
        RLMConfig,
        compute_hash,
        load_cache,
        save_cache
    )
except ImportError as e:
    print(f"[ERROR] Could not import local rlm_config from {SCRIPT_DIR}: {e}")
    sys.exit(1)


def main() -> None:
    parser = argparse.ArgumentParser(description="RLM Agent Injection — Write summaries directly to cache")
    parser.add_argument("--profile", required=True, help="RLM profile name (from rlm_profiles.json)")
    parser.add_argument("--file", "-f", required=True, help="Single file to process (relative to project root)")
    parser.add_argument("--summary", required=True, help="The summary string to inject")

    args = parser.parse_args()

    try:
        config = RLMConfig(profile_name=args.profile)
        
        f_path = (PROJECT_ROOT / args.file).resolve()
        if not f_path.exists():
            print(f"[ERROR] Target file not found on disk: {args.file}")
            sys.exit(1)

        rel_path = str(f_path.relative_to(PROJECT_ROOT))
        
        # Read the file to generate the content hash
        content = f_path.read_text(encoding="utf-8", errors="ignore")
        content_hash = compute_hash(content)

        # Save directly to the specific markdown file without reloading the entire 5000+ cache
        # Cross-platform: uses fcntl on POSIX, no-op on Windows
        lock_path = config.cache_path.with_suffix(".lock")
        with _file_lock(lock_path):
            cache_dir = config.cache_path.with_suffix('')
            rel_path_clean = rel_path[:-3] if rel_path.endswith(".md") else rel_path
            norm_key = rel_path_clean.replace("\\", "/")
            md_file = cache_dir / f"{norm_key}.md"
            md_file.parent.mkdir(parents=True, exist_ok=True)
            
            entry = {
                "hash": content_hash,
                "summary": args.summary,
                "summarized_at": datetime.now().isoformat()
            }
            
            lines = ["---"]
            for k, v in entry.items():
                if k != "summary":
                    val = str(v).replace('"', "'")
                    lines.append(f'{k}: "{val}"')
            lines.append("---")
            lines.append("")
            lines.append("# Summary")
            lines.append(str(entry.get("summary", "")))
            lines.append("")
            
            md_file.write_text("\n".join(lines), encoding="utf-8")
        
        print(f"[OK] Successfully injected summary for {rel_path} into {cache_dir.name}")

    except Exception as e:
        print(f"[ERROR] Fatal error during injection: {e}")
        sys.exit(1)


if __name__ == "__main__":
    main()
